CREATE TABLE IF NOT EXISTS company_profile (
  id SERIAL PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  content TEXT NOT NULL,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

INSERT INTO company_profile (name, content)
SELECT
  'Andersen Lab',
  E'# Company Overview\n\nAndersen Lab is a well-established, global software development and IT consulting company with a strong reputation for technical excellence and enterprise-grade delivery.\n\n## Key Facts\n\n| Attribute | Detail |\n|---|---|\n| Founded | 2007 |\n| Headquarters | Warsaw, Poland |\n| Employee Count | 3,700+ professionals (as of 2026) |\n| Global Reach | 16+ development centers across Europe, the USA, the UK, and the UAE |\n| Project Portfolio | Successfully delivered over 1,000 projects globally |\n\n## Comprehensive Service Capabilities\n\nAndersen Lab provides a full-spectrum, end-to-end suite of IT services, making them a versatile one-stop partner for complex digital transformations.\n\n- **Core Development**: Custom software, web, and mobile application development.\n- **Strategic Consulting**: Technology advisory, business analysis, and enterprise system architecture.\n- **Quality & Security**: Robust QA, IT security management, and rigorous testing protocols.\n- **Modernization**: Legacy application modernization and long-term maintenance support.\n- **Emerging Technologies**: Deep expertise in AI, Machine Learning, Data Science, Big Data, and Visual Technologies.\n- **Additional Expertise**: UI/UX design, project management, team augmentation, and DevOps implementation.\n\n## Deep Industry Expertise\n\nThe company has cultivated specialized, vertical-specific knowledge across multiple sectors:\n\n- Financial Services (FinTech)\n- Healthcare\n- Logistics\n- Automotive\n- Media & Entertainment\n- eCommerce\n\n## Proven Track Record & Growth History\n\nWith over 18 years of continuous operation, Andersen Lab has demonstrated sustained growth and global scalability.\n\n- Year-over-Year Growth: Expanded from ~3,200 employees in early 2023 to nearly 3,800 by mid-2026, indicating strong market demand and financial health.\n- Global Expansion: Successfully established a presence on 6 continents, reflecting the capability to manage distributed, international teams.\n\n## Prestigious Clientele\n\nAndersen Lab has earned the trust of demanding enterprise corporations worldwide, including:\n\n- Siemens\n- S&P Global\n- Ryanair\n- Johnson & Johnson\n- TUI\n\n## Industry Recognition & Awards\n\n- Ranked among the world\'s Top 1,000 B2B service providers.\n- Shortlisted among the Top IT Consultants in London by Clutch.\n- Recognized for outstanding delivery on the Gartner Peer Insights platform.\n\n## Client Satisfaction Highlights\n\n- **Reviews.io Rating**: 4.8/5 average based on client reviews.\n- **Verified Testimonials**: 213 verified testimonials on the UK site, consistently highlighting:\n  - Unwavering commitment to excellence.\n  - Clear and transparent communication.\n  - Consistent adherence to deadlines.\n  - Complex problem solving and resilience, including handling critical situations such as cyberattacks.\n- **Enterprise Validation**: A Gartner Peer Insights user from a large retail corporation (10B–30B USD) described service as "very solid" with a proven track record of "delivering high quality projects".\n\n## Overall Strengths\n\nAndersen Lab is a legitimate, large-scale, and technically proficient organization. Its impressive client roster, extensive global footprint, and decade-and-a-half of operational history position it as a highly capable and reliable partner for enterprises seeking robust, high-quality software development and IT consulting services.'
WHERE NOT EXISTS (
  SELECT 1 FROM company_profile WHERE name = 'Andersen Lab'
);
